def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.full_like(bins, np.inf, dtype=float)
    n = len(bins)
    for i in range(n):
        capacity = bins[i]
        if capacity <= 0:
            continue
        ratio = item / capacity
        if ratio > 1:
            continue
        score = 0
        for j in range(1, 21):
            weight = 1 / (j ** 2)
            term = (ratio ** j) * weight
            if j % 3 == 0:
                term *= 1.5
            elif j % 2 == 0:
                term *= 1.2
            else:
                term *= 0.85
            score += term
            if score > 2:
                break
        leftover = capacity - item
        if leftover < 0.05 * capacity:
            score *= 2.0
        elif leftover < 0.15 * capacity:
            score *= 1.5
        elif leftover < 0.3 * capacity:
            score *= 1.1
        else:
            score *= 0.85
        if score < 0.05:
            score += 0.1 * leftover
        if i % 4 == 0:
            score *= 1.2
        if i % 5 == 0 and leftover > 0.5 * capacity:
            score *= 0.9
        if i % 7 == 0:
            score += 0.05 * np.cos(i + item)
        if leftover < 0.1 * capacity and ratio > 0.8:
            for k in range(3):
                score += 0.02 * np.sin(k * i + item)
        priorities[i] = score
    finite_priorities = priorities[np.isfinite(priorities)]
    if finite_priorities.size == 0:
        max_priority = 1.0
    else:
        max_priority = np.max(finite_priorities)
    for i in range(n):
        if priorities[i] == np.inf:
            priorities[i] = max_priority * 4
    for i in range(n):
        if priorities[i] < 0.15:
            priorities[i] += 0.1 * np.sin(i * item + priorities[i])
        if priorities[i] > max_priority * 2:
            priorities[i] *= 0.95
    return priorities
